    "example_question_sqls": [
      {
        "id": "01f0621fbdad19f981dd24ed2978838b",
        "question": [
          "give me all users that are diamond in the UK region and have do not have moneyfarm"
        ],
        "sql": [
          "SELECT\n",
          "  `CID`\n",
          "FROM\n",
          "  `main`.`bi_output_stg`.`bi_output_genie_club`\n",
          "WHERE\n",
          "  `CurrentTier` = 'Diamond'\n",
          "  AND `Region` = 'UK'\n",
          "  AND `MoneyFarmBalance` = 0"
        ]
      },
      {
        "id": "01f06315a7ea1e68a74fc1047c978716",
        "question": [
          "How many Diamond in Ireland?"
        ],
        "sql": [
          "SELECT\n",
          "  COUNT(DISTINCT `CID`)\n",
          "FROM\n",
          "  `main`.`bi_output_stg`.`bi_output_genie_club`\n",
          "WHERE\n",
          "  `CurrentTier` = 'Diamond'\n",
          "  AND `Country` = 'Ireland'"
        ]
      }
